mapper.select:
SELECT a.type, a.parent_id, b.cate_name, b.display_seq, a.device, a.cnt FROM ( SELECT type, parent_id, device, SUM(cnt) AS cnt FROM ELIB_STATISTICS_TBL4 WHERE 1=1
AND lib = #{library_code}
AND #{search_sdt} <= dt
AND dt <= #{search_edt}
GROUP BY type, parent_id, device ) a, ELIB_CATEGORY b WHERE 1=1 AND a.parent_id = b.cate_id (+) ORDER BY a.type, b.display_seq, a.device

mapper.sql:
	from (
	  select book_idx, LISTAGG(device || ':' || cnt, ',') within group ( order by book_idx ) as device_cnt, sum(cnt) as cnt
	  from (
	    select book_idx, device, count(device) as cnt
	    from (
		  select a.book_idx, a.device
		  from  a, elib_book b
		  where 1=1
		  and a.book_idx = b.book_idx
		  and b.type = #{type}

		  AND b.library_code = #{library_code}


		  AND #{search_sdt} <= TO_CHAR(a., 'YYYY-MM-DD')
		  AND TO_CHAR(a., 'YYYY-MM-DD') <= #{search_edt}


          AND 1=2


		  union all
		  select a.book_idx, a.device
		  from elib_lend a, elib_book b
		  where 1=1
		  and a.book_idx = b.book_idx
		  and b.type = #{type}

		  AND b.library_code = #{library_code}


		  AND #{search_sdt} <= TO_CHAR(a.lend_dt, 'YYYY-MM-DD')
		  AND TO_CHAR(a.lend_dt, 'YYYY-MM-DD') <= #{search_edt}


          AND 1=2


		)
		group by book_idx, device
	  )
	  group by book_idx
	  order by book_idx
	) a,
	  elib_book b
	where 1=1
	and b.type = #{type}
	and a.book_idx = b.book_idx

	order by a.cnt desc, a.book_idx

mapper.select:
${pagingTop} select a.book_idx, b.book_name, a.device_cnt, b.library_code, a.cnt, CASE WHEN b.library_code = '9999999' THEN '통합' ELSE (SELECT z.homepage_name FROM CMS_HOMEPAGE z WHERE b.library_code = SUBSTR(z.homepage_code, 1, 8)) END AS library_name, (SELECT z.cate_name FROM ELIB_CATEGORY z WHERE z.cate_id = b.parent_id) AS parent_name, (SELECT z.comp_name FROM ELIB_COMPANY z WHERE INSTR(z.com_code, b.com_code) > 0) AS comp_name, ( SELECT COUNT(*) FROM ELIB_RESERVE z WHERE b.book_idx = z.book_idx
AND #{search_sdt} <= TO_CHAR(z.reserve_dt, 'YYYY-MM-DD')
AND TO_CHAR(z.reserve_dt, 'YYYY-MM-DD') <= #{search_edt}
) AS total_reserves_cnt, ( SELECT COUNT(*) FROM ELIB_COMMENT z WHERE b.book_idx = z.book_idx
AND #{search_sdt} <= TO_CHAR(z.regdt, 'YYYY-MM-DD')
AND TO_CHAR(z.regdt, 'YYYY-MM-DD') <= #{search_edt}
) AS comments_cnt, b.book_reserve as reserves_cnt
${pagingBottom}

		select
		  a.device_cnt, a.cnt,
		  (
		    SELECT COUNT(*)
		    FROM ELIB_RESERVE z, ELIB_BOOK y
		    WHERE 1=1
		    AND z.book_idx = y.book_idx
		    AND y.type = #{type}

			AND y.library_code = #{library_code}


		    AND #{search_sdt} <= TO_CHAR(z.reserve_dt, 'YYYY-MM-DD')


		    AND TO_CHAR(z.reserve_dt, 'YYYY-MM-DD') <= #{search_edt}

		  ) AS total_reserves_cnt,
		  (
		    SELECT COUNT(*)
		    FROM ELIB_COMMENT z, ELIB_BOOK y
		    WHERE 1=1
		    AND z.book_idx = y.book_idx
		    AND y.type = #{type}

			AND y.library_code = #{library_code}


		    AND #{search_sdt} <= TO_CHAR(z.regdt, 'YYYY-MM-DD')


		    AND TO_CHAR(z.regdt, 'YYYY-MM-DD') <= #{search_edt}

		  ) AS comments_cnt,
  		  (
		    SELECT sum(y.book_reserve)
		    FROM ELIB_RESERVE z, ELIB_BOOK y
		    WHERE z.book_idx = y.book_idx
		    AND y.type = #{type}

			AND y.library_code = #{library_code}


		    AND #{search_sdt} <= TO_CHAR(z.reserve_dt, 'YYYY-MM-DD')


		    AND TO_CHAR(z.reserve_dt, 'YYYY-MM-DD') <= #{search_edt}

		  ) as reserves_cnt
		from (
		  select LISTAGG(device || ':' || cnt, ',') within group ( order by 1 ) as device_cnt, sum(cnt) as cnt
		  from (
		  	select a.device, count(a.device) as cnt
		  	from (
			  select a.device
			  from  a, elib_book b
			  where 1=1
			  and a.book_idx = b.book_idx
			  and b.type = #{type}

			  AND b.library_code = #{library_code}


			  AND #{search_sdt} <= TO_CHAR(a., 'YYYY-MM-DD')
			  AND TO_CHAR(a., 'YYYY-MM-DD') <= #{search_edt}


	          AND 1=2


			  union all
			  select a.device
			  from elib_lend a, elib_book b
			  where 1=1

			  AND b.library_code = #{library_code}

			  and a.book_idx = b.book_idx
			  and b.type = #{type}

			  AND #{search_sdt} <= TO_CHAR(a.lend_dt, 'YYYY-MM-DD')
			  AND TO_CHAR(a.lend_dt, 'YYYY-MM-DD') <= #{search_edt}


	          AND 1=2


			) a
			group by a.device
		  )
		  group by 1
		  order by 1
		) a
		where 1=1

select a.book_idx, b.book_name, a.device_cnt, b.library_code, a.cnt, CASE WHEN b.library_code = '9999999' THEN '통합' ELSE (SELECT z.homepage_name FROM CMS_HOMEPAGE z WHERE b.library_code = SUBSTR(z.homepage_code, 1, 8)) END AS library_name, (SELECT z.cate_name FROM ELIB_CATEGORY z WHERE z.cate_id = b.parent_id) AS parent_name, (SELECT z.comp_name FROM ELIB_COMPANY z WHERE INSTR(z.com_code, b.com_code) > 0) AS comp_name, ( SELECT COUNT(*) FROM ELIB_RESERVE z WHERE z.book_idx = b.book_idx
AND #{search_sdt} <= TO_CHAR(z.reserve_dt, 'YYYY-MM-DD')
AND TO_CHAR(z.reserve_dt, 'YYYY-MM-DD') <= #{search_edt}
) AS total_reserves_cnt, ( SELECT COUNT(*) FROM ELIB_COMMENT z WHERE z.book_idx = b.book_idx
AND #{search_sdt} <= TO_CHAR(z.regdt, 'YYYY-MM-DD')
AND TO_CHAR(z.regdt, 'YYYY-MM-DD') <= #{search_edt}
) AS comments_cnt, ( SELECT sum(y.book_reserve) FROM ELIB_RESERVE z, ELIB_BOOK y WHERE z.book_idx = y.book_idx AND y.type = #{type}
AND #{search_sdt} <= TO_CHAR(z.reserve_dt, 'YYYY-MM-DD')
AND TO_CHAR(z.reserve_dt, 'YYYY-MM-DD') <= #{search_edt}
) as reserves_cnt

mapper.sql:
FROM ELIB_MEMBER ta, ( SELECT c.member_id, (SELECT z.loca FROM GBELAS.TN_ST_USER z WHERE z.web_id = c.member_id) AS library_code, SUM(c.pcnt) AS pcnt, SUM(c.scnt) AS scnt, SUM(c.acnt) AS acnt, SUM(c.icnt) AS icnt, SUM(c.ecnt) AS ecnt, SUM(c.comments_cnt) AS comments_cnt FROM ( SELECT a.member_id, c.loca AS library_code, COUNT(*) AS pcnt, 0 AS scnt, 0 AS acnt, 0 AS icnt, 0 AS ecnt, 0 AS comments_cnt FROM
ELIB_BOOK b, GBELAS.TN_ST_USER c WHERE a.book_idx = b.book_idx AND a.member_id = c.web_id (+) AND b.type = #{type} AND a.device = 'P'
AND #{search_sdt} <= TO_CHAR(, 'YYYY-MM-DD')
AND TO_CHAR(, 'YYYY-MM-DD') <= #{search_edt}
AND c.loca = #{library_code}
AND b.com_code = #{com_code}
AND a.member_id = #{member_id}
GROUP BY a.member_id, c.loca UNION ALL SELECT a.member_id, c.loca AS library_code, 0 AS pcnt, COUNT(*) AS scnt, 0 AS acnt, 0 AS icnt, 0 AS ecnt, 0 AS comments_cnt FROM
ELIB_BOOK b, GBELAS.TN_ST_USER c WHERE a.book_idx = b.book_idx AND a.member_id = c.web_id (+) AND b.type = #{type} AND a.device = 'S'
AND #{search_sdt} <= TO_CHAR(, 'YYYY-MM-DD')
AND TO_CHAR(, 'YYYY-MM-DD') <= #{search_edt}
AND c.loca = #{library_code}
AND b.com_code = #{com_code}
AND a.member_id = #{member_id}
GROUP BY a.member_id, c.loca UNION ALL SELECT a.member_id, c.loca AS library_code, 0 AS pcnt, 0 AS scnt, COUNT(*) AS acnt, 0 AS icnt, 0 AS ecnt, 0 AS comments_cnt FROM
ELIB_BOOK b, GBELAS.TN_ST_USER c WHERE a.book_idx = b.book_idx AND a.member_id = c.web_id (+) AND b.type = #{type} AND a.device = 'A'
AND #{search_sdt} <= TO_CHAR(, 'YYYY-MM-DD')
AND TO_CHAR(, 'YYYY-MM-DD') <= #{search_edt}
AND c.loca = #{library_code}
AND b.com_code = #{com_code}
AND a.member_id = #{member_id}
GROUP BY a.member_id, c.loca UNION ALL SELECT a.member_id, c.loca AS library_code, 0 AS pcnt, 0 AS scnt, 0 AS acnt, COUNT(*) AS icnt, 0 AS ecnt, 0 AS comments_cnt FROM
ELIB_BOOK b, GBELAS.TN_ST_USER c WHERE a.book_idx = b.book_idx AND a.member_id = c.web_id (+) AND b.type = #{type} AND a.device = 'I'
AND #{search_sdt} <= TO_CHAR(, 'YYYY-MM-DD')
AND TO_CHAR(, 'YYYY-MM-DD') <= #{search_edt}
AND c.loca = #{library_code}
AND b.com_code = #{com_code}
AND a.member_id = #{member_id}
GROUP BY a.member_id, c.loca UNION ALL SELECT a.member_id, c.loca AS library_code, 0 AS pcnt, 0 AS scnt, 0 AS acnt, 0 AS icnt, COUNT(*) AS ecnt, 0 AS comments_cnt FROM
ELIB_BOOK b, GBELAS.TN_ST_USER c WHERE a.book_idx = b.book_idx AND a.member_id = c.web_id (+) AND b.type = #{type} AND a.device = 'E'
AND #{search_sdt} <= TO_CHAR(, 'YYYY-MM-DD')
AND TO_CHAR(, 'YYYY-MM-DD') <= #{search_edt}
AND c.loca = #{library_code}
AND b.com_code = #{com_code}
AND a.member_id = #{member_id}
GROUP BY a.member_id, c.loca UNION ALL SELECT a.member_id, c.loca AS library_code, 0 AS pcnt, 0 AS scnt, 0 AS acnt, 0 AS icnt, 0 AS ecnt, COUNT(*) AS comments_cnt FROM ELIB_COMMENT a, ELIB_BOOK b, GBELAS.TN_ST_USER c WHERE a.book_idx = b.book_idx AND a.member_id = c.web_id (+) AND b.type = #{type}
AND #{search_sdt} <= TO_CHAR(a.regdt, 'YYYY-MM-DD')
AND TO_CHAR(a.regdt, 'YYYY-MM-DD') <= #{search_edt}
AND a.member_id = #{member_id}
GROUP BY a.member_id, c.loca ) c GROUP BY member_id, library_code ) tb WHERE ta.member_id = tb.member_id
ORDER BY ta.member_id
ORDER BY NVL(tb.pcnt, 0) DESC
ORDER BY NVL(tb.scnt, 0) DESC
ORDER BY (NVL(tb.pcnt, 0) + NVL(tb.acnt, 0) + NVL(tb.icnt, 0) + NVL(tb.scnt, 0) + NVL(tb.ecnt, 0)) DESC
ORDER BY tb.comments_cnt DESC
ORDER BY (NVL(tb.pcnt, 0) + NVL(tb.scnt, 0)) DESC

mapper.select:
SELECT CASE WHEN type = '1' THEN '전자책' WHEN type = '2' THEN '오디오북' WHEN type = '3' THEN '온라인강좌' WHEN type = '4' THEN '전자저널' ELSE '불명' END AS type, CASE WHEN age = '1' THEN '어린이' WHEN age = '2' THEN '청소년' WHEN age = '3' THEN '성인' ELSE '불명' END AS age_group, CASE WHEN sex = '2' THEN '여' WHEN sex = '1' THEN '남' ELSE '불명' END AS sex, SUM(cnt) AS lend_cnt FROM ELIB_STATISTICS_TBL1 WHERE 1=1
AND lib = #{library_code}
AND #{search_sdt} <= dt
AND dt <= #{search_edt}
GROUP BY type, age, sex

SELECT CASE WHEN type = '1' THEN '전자책' WHEN type = '2' THEN '오디오북' WHEN type = '3' THEN '온라인강좌' WHEN type = '4' THEN '전자저널' ELSE '불명' END AS type, CASE WHEN age = '1' THEN '어린이' WHEN age = '2' THEN '청소년' WHEN age = '3' THEN '성인' ELSE '불명' END AS age_group, CASE WHEN sex = '2' THEN '여' WHEN sex = '1' THEN '남' ELSE '불명' END AS sex, SUM(cnt) AS lend_cnt FROM ELIB_STATISTICS_TBL2 WHERE 1=1
AND lib = #{library_code}
AND lib = '-'
AND #{search_sdt} <= dt
AND dt <= #{search_edt}
GROUP BY type, age, sex

SELECT type, com_code, device, SUM(cnt) AS cnt FROM ( SELECT dt, lib, type, com_code, device, cnt FROM ELIB_STATISTICS_TBL3 WHERE 1=1
AND lib = #{library_code}
UNION ALL
SELECT #{search_edt} AS dt, y.library_code AS lib, y.type, y.com_code, '-' AS device, COUNT(*) AS cnt
SELECT TO_CHAR(SYSDATE, 'YYYY-MM-DD') AS dt, y.library_code AS lib, y.type, y.com_code, '-' AS device, COUNT(*) AS cnt
FROM ELIB_BOOK y WHERE 1=1
AND y.library_code = #{library_code}
AND y.type IS NOT NULL AND y.use_yn = 'Y' AND y.approved_yn = 'Y' GROUP BY TO_CHAR(SYSDATE, 'YYYY-MM-DD'), y.library_code, y.type, y.com_code ) WHERE 1=1
AND lib = #{library_code}
AND #{search_sdt} <= dt
AND dt <= #{search_edt}
GROUP BY type, com_code, device

SELECT CASE WHEN type = '1' THEN '전자책' WHEN type = '2' THEN '오디오북' WHEN type = '3' THEN '온라인강좌' WHEN type = '4' THEN '전자저널' ELSE '불명' END AS type, CASE WHEN age = '1' THEN '어린이' WHEN age = '2' THEN '청소년' WHEN age = '3' THEN '성인' ELSE '불명' END AS age_group, CASE WHEN sex = '2' THEN '여' WHEN sex = '1' THEN '남' ELSE '불명' END AS sex, SUM(cnt) AS lend_cnt FROM ELIB_STATICS_AGE_PERSONAL1 WHERE 1=1
AND lib = #{library_code}
AND #{search_sdt} <= dt
AND dt <= #{search_edt}
GROUP BY type, age, sex

SELECT CASE WHEN type = '1' THEN '전자책' WHEN type = '2' THEN '오디오북' WHEN type = '3' THEN '온라인강좌' WHEN type = '4' THEN '전자저널' ELSE '불명' END AS type, CASE WHEN age = '1' THEN '어린이' WHEN age = '2' THEN '청소년' WHEN age = '3' THEN '성인' ELSE '불명' END AS age_group, CASE WHEN sex = '2' THEN '여' WHEN sex = '1' THEN '남' ELSE '불명' END AS sex, SUM(cnt) AS lend_cnt FROM ELIB_STATICS_AGE_PERSONAL2 WHERE 1=1
AND lib = #{library_code}
AND lib = '-'
AND #{search_sdt} <= dt
AND dt <= #{search_edt}
GROUP BY type, age, sex

SELECT a.type, a.parent_id, b.cate_name, b.display_seq, a.device, a.cnt FROM ( SELECT type, parent_id, device, SUM(cnt) AS cnt FROM ELIB_STATICS_CATEGORY_PERSONAL WHERE 1=1
AND lib = #{library_code}
AND #{search_sdt} <= dt
AND dt <= #{search_edt}
GROUP BY type, parent_id, device ) a, ELIB_CATEGORY b WHERE 1=1 AND a.parent_id = b.cate_id (+) ORDER BY a.type, b.display_seq, a.device

SELECT type, com_code, device, SUM(cnt) AS cnt FROM ( SELECT dt, lib, type, com_code, device, cnt FROM ELIB_STATICS_COMPANY_PERSONAL WHERE 1=1
AND lib = #{library_code}
UNION ALL
SELECT #{search_edt} AS dt, y.library_code AS lib, y.type, y.com_code, '-' AS device, COUNT(*) AS cnt
SELECT TO_CHAR(SYSDATE, 'YYYY-MM-DD') AS dt, y.library_code AS lib, y.type, y.com_code, '-' AS device, COUNT(*) AS cnt
FROM ELIB_BOOK y WHERE 1=1
AND y.library_code = #{library_code}
AND y.type IS NOT NULL AND y.use_yn = 'Y' AND y.approved_yn = 'Y' GROUP BY TO_CHAR(SYSDATE, 'YYYY-MM-DD'), y.library_code, y.type, y.com_code ) WHERE 1=1
AND lib = #{library_code}
AND #{search_sdt} <= dt
AND dt <= #{search_edt}
GROUP BY type, com_code, device
